  assertEqual(result.rows[0]["address"], '123 "Main" Street', "Escaped quotes in quoted field");
  assertEqual(result.rows[1]["address"], "456 Oak Lane", "Regular quoted field");
}

// Test 46: Pipe delimiter with quoted fields
function testPipeDelimiterWithQuotes(): void {
  const csv = `name|description
John|"Contains | pipe"
Jane|"Simple field"`;

  const result = parseCSV(csv, { delimiter: "|" });

  assertEqual(result.rows[0]["description"], "Contains | pipe", "Pipe inside quotes should be preserved");
}

// Test 47: Tab delimiter
function testTabDelimiter(): void {
  const csv = `name\tage\tcity
John\t30\tNew York
Jane\t25\tLA`;

  const result = parseCSV(csv, { delimiter: "\t" });

  assertEqual(result.headers, ["name", "age", "city"], "Tab delimiter should work");
  assertEqual(result.rows[0]["name"], "John", "Tab-separated values should parse");
}

// Test 48: Semicolon delimiter (common in EU)
function testSemicolonDelimiter(): void {
  const csv = `name;value;status
John;100;active
Jane;200;inactive`;

  const result = parseCSV(csv, { delimiter: ";" });

  assertEqual(result.rows.length, 2, "Semicolon delimiter should work");
  assertEqual(result.rows[0]["value"], 100, "Values should be parsed correctly");
}

// Test 49: Windows CRLF line endings
function testWindowsCRLFLineEndings(): void {
  const csv = `name,age\r\nJohn,30\r\nJane,25`;

  const result = parseCSV(csv, { lineSeparator: "\r\n" });

  assertEqual(result.headers, ["name", "age"], "CRLF line endings should work");
  assertEqual(result.rows.length, 2, "Should have 2 data rows");
  assertEqual(result.rows[0]["name"], "John", "First row should parse correctly");
}

// Test 50: Trailing newline handling
function testTrailingNewline(): void {
  const csv = `name,age
John,30
Jane,25
`;

  const result = parseCSV(csv);

  assertEqual(result.rows.length, 2, "Trailing newline should be ignored");
  assertEqual(result.rows[1]["name"], "Jane", "Last row should be correct");
}

// Run all tests
function runAllTests(): void {
  const tests = [
    { name: "Basic parsing", fn: testBasicParsing },
    { name: "Quoted fields with commas", fn: testQuotedFieldsWithCommas },
    { name: "Escaped quotes", fn: testEscapedQuotes },
    { name: "Custom delimiter", fn: testCustomDelimiter },
    { name: "Custom quote character", fn: testCustomQuoteCharacter },
    { name: "Custom line separator", fn: testCustomLineSeparator },
    { name: "Type coercion - numbers", fn: testTypeCoercionNumbers },
    { name: "Type coercion - booleans", fn: testTypeCoercionBooleans },
    { name: "Type coercion - null", fn: testTypeCoercionNull },
    { name: "Type coercion - strings", fn: testTypeCoercionStrings },
    { name: "Malformed rows - wrong field count", fn: testMalformedRowsWrongFieldCount },
    { name: "Malformed rows - unclosed quotes", fn: testMalformedRowsUnclosedQuotes },
    { name: "Error collection", fn: testErrorCollection },
    { name: "Filter method", fn: testFilterMethod },
    { name: "Filter multiple conditions", fn: testFilterMultipleConditions },
    { name: "Sum aggregation", fn: testSumAggregation },
    { name: "Sum with null values", fn: testSumWithNullValues },
    { name: "Average aggregation", fn: testAverageAggregation },
    { name: "Average with null values", fn: testAverageWithNullValues },
    { name: "Count aggregation", fn: testCountAggregation },
    { name: "GroupBy aggregation", fn: testGroupByAggregation },
    { name: "GroupBy with null values", fn: testGroupByWithNullValues },
    { name: "Chained operations", fn: testChainedOperations },
    { name: "Empty input", fn: testEmptyInput },
    { name: "Only headers", fn: testOnlyHeaders },
    { name: "Single column", fn: testSingleColumn },
    { name: "Single row", fn: testSingleRow },
    { name: "Very long field", fn: testVeryLongField },
    { name: "Special characters", fn: testSpecialCharacters },
    { name: "Whitespace handling", fn: testWhitespaceHandling },
    { name: "Quoted whitespace preservation", fn: testQuotedWhitespacePreservation },
    { name: "Empty quoted field", fn: testEmptyQuotedField },
    { name: "Multiple consecutive delimiters", fn: testMultipleDelimiters },
    { name: "Filter returns methods intact", fn: testFilterReturnsMethodsIntact },
    { name: "Aggregation on empty result", fn: testAggregationOnEmptyResult },
    { name: "Negative numbers", fn: testNegativeNumbers },
    { name: "Scientific notation", fn: testScientificNotation },
    { name: "Zero values", fn: testZeroValues },
    { name: "Boolean case sensitivity", fn: testBooleanCaseSensitivity },
    { name: "Headers with spaces", fn: testHeadersWithSpaces },
    { name: "Duplicate headers", fn: testDuplicateHeaders },
    { name: "Sum on non-numeric column", fn: testSumOnNonNumericColumn },
    { name: "GroupBy on numeric column", fn: testGroupByOnNumericColumn },
    { name: "Mixed type columns", fn: testMixedTypeColumns },
    { name: "Complex quoted and escaped field", fn: testComplexQuotedAndEscaped },
    { name: "Pipe delimiter with quotes", fn: testPipeDelimiterWithQuotes },
    { name: "Tab delimiter", fn: testTabDelimiter },
    { name: "Semicolon delimiter", fn: testSemicolonDelimiter },
    { name: "Windows CRLF line endings", fn: testWindowsCRLFLineEndings },
    { name: "Trailing newline handling", fn: testTrailingNewline },
  ];

  let passed = 0;
  let failed = 0;
  const failures: string[] = [];

  console.log(`\n${"=".repeat(70)}`);
  console.log(`Running ${tests.length} CSV Parser Tests`);
  console.log(`${"=".repeat(70)}\n`);

  for (const test of tests) {
    try {
      test.fn();
      console.log(`✓ ${test.name}`);
      passed++;
    } catch (error) {
      console.log(`✗ ${test.name}`);
      failed++;
      failures.push(`\n${test.name}:\n${error instanceof Error ? error.message : String(error)}`);
    }
  }

  console.log(`\n${"=".repeat(70)}`);
  console.log(`Results: ${passed} passed, ${failed} failed out of ${tests.length} tests`);
  console.log(`${"=".repeat(70)}\n`);

  if (failures.length > 0) {
    console.log("FAILURES:");
    console.log(failures.join("\n"));
    process.exit(1);
  } else {
    console.log("All tests passed! 🎉");
    process.exit(0);
  }
}

// Export for testing
export { runAllTests };

// Run tests if this is the main module
if (require.main === module) {
  runAllTests();
}

