/**
 * Example usage of the CSV Parser library
 */

import { parseCSV } from "./csv-parser";

// ============================================================================
// Example 1: Basic CSV Parsing
// ============================================================================

function example1BasicParsing() {
  console.log("\n=== Example 1: Basic CSV Parsing ===\n");

  const csv = `name,age,city
John,30,New York
Jane,25,Los Angeles
Bob,35,Chicago`;

  const result = parseCSV(csv);

  console.log("Headers:", result.headers);
  console.log("Rows:", result.rows);
  console.log("Errors:", result.errors);
}

// ============================================================================
// Example 2: Quoted Fields with Embedded Commas
// ============================================================================

function example2QuotedFields() {
  console.log("\n=== Example 2: Quoted Fields with Embedded Commas ===\n");

  const csv = `name,address,phone
"Smith, John","123 Main St, Apt 4","555-1234"
"Doe, Jane","456 Oak Lane, Suite B","555-5678"`;

  const result = parseCSV(csv);

  console.log("Name:", result.rows[0].name);
  console.log("Address:", result.rows[0].address);
  console.log("Phone:", result.rows[0].phone);
}

// ============================================================================
// Example 3: Escaped Quotes
// ============================================================================

function example3EscapedQuotes() {
  console.log("\n=== Example 3: Escaped Quotes ===\n");

  const csv = `speaker,quote
John,"He said ""Hello, World!"""
Jane,"It""s a ""wonderful"" day"`;

  const result = parseCSV(csv);

  console.log("John's quote:", result.rows[0].quote);
  console.log("Jane's quote:", result.rows[1].quote);
}

// ============================================================================
// Example 4: Type Coercion
// ============================================================================

function example4TypeCoercion() {
  console.log("\n=== Example 4: Type Coercion ===\n");

  const csv = `name,age,salary,active,verified
John,30,50000.50,true,null
Jane,25,45000,false,false
Bob,35,60000,TRUE,true`;

  const result = parseCSV(csv);

  for (const row of result.rows) {
    console.log(`${row.name}:`);
    console.log(`  age: ${row.age} (${typeof row.age})`);
    console.log(`  salary: ${row.salary} (${typeof row.salary})`);
    console.log(`  active: ${row.active} (${typeof row.active})`);
    console.log(`  verified: ${row.verified} (${row.verified === null ? "null" : typeof row.verified})`);
  }
}

// ============================================================================
// Example 5: Custom Delimiters
// ============================================================================

function example5CustomDelimiters() {
  console.log("\n=== Example 5: Custom Delimiters ===\n");

  // Pipe delimiter
  const pipeCSV = `name|age|city
John|30|New York
Jane|25|Los Angeles`;

  const pipeResult = parseCSV(pipeCSV, { delimiter: "|" });
  console.log("Pipe-delimited:", pipeResult.rows[0]);

  // Tab delimiter
  const tabCSV = `name\tage\tcity
John\t30\tNew York
Jane\t25\tLos Angeles`;

  const tabResult = parseCSV(tabCSV, { delimiter: "\t" });
  console.log("Tab-delimited:", tabResult.rows[0]);

  // Semicolon (common in EU)
  const semiCSV = `name;age;city
John;30;New York
Jane;25;Los Angeles`;

  const semiResult = parseCSV(semiCSV, { delimiter: ";" });
  console.log("Semicolon-delimited:", semiResult.rows[0]);
}

// ============================================================================
// Example 6: Error Handling
// ============================================================================

function example6ErrorHandling() {
  console.log("\n=== Example 6: Error Handling ===\n");

  const csv = `name,age,city
John,30,New York
Jane,25
Bob,35,Chicago,Extra`;

  const result = parseCSV(csv);

  console.log(`Successfully parsed: ${result.rows.length} rows`);
  console.log(`Errors encountered: ${result.errors.length}`);

  if (result.errors.length > 0) {
    console.log("\nError details:");
    for (const error of result.errors) {
      console.log(`  Row ${error.row}: ${error.message}`);
    }
  }

  console.log("\nValid rows:");
  for (const row of result.rows) {
    console.log(`  ${row.name}, ${row.age}, ${row.city}`);
  }
}

// ============================================================================
// Example 7: Filtering
// ============================================================================

function example7Filtering() {
  console.log("\n=== Example 7: Filtering ===\n");

  const csv = `name,age,department
John,30,Engineering
Jane,25,Sales
Bob,35,Engineering
Alice,28,HR`;

  const result = parseCSV(csv);

  // Filter by age >= 30
  const seniors = result.filter((row) => row.age >= 30);
  console.log("Employees age 30+:");
  for (const row of seniors.rows) {
    console.log(`  ${row.name}, ${row.age}`);
  }

  // Filter by department
  const engineers = result.filter((row) => row.department === "Engineering");
  console.log("\nEngineers:");
  for (const row of engineers.rows) {
    console.log(`  ${row.name}, ${row.age}`);
  }

  // Chained filters
  const seniorEngineers = result
    .filter((row) => row.age >= 30)
    .filter((row) => row.department === "Engineering");
  console.log("\nSenior Engineers (age 30+):");
  for (const row of seniorEngineers.rows) {
    console.log(`  ${row.name}, ${row.age}`);
  }
}

// ============================================================================
// Example 8: Aggregation - Sum
// ============================================================================

function example8Sum() {
  console.log("\n=== Example 8: Sum Aggregation ===\n");

  const csv = `product,quantity,price
Widget,100,10.50
Gadget,50,25.00
Doohickey,75,15.00`;

  const result = parseCSV(csv);

  const totalQuantity = result.sum("quantity");
  const totalPrice = result.sum("price");

  console.log(`Total quantity sold: ${totalQuantity}`);
  console.log(`Total price: $${totalPrice.toFixed(2)}`);
}

// ============================================================================
// Example 9: Aggregation - Average
// ============================================================================

function example9Average() {
  console.log("\n=== Example 9: Average Aggregation ===\n");

  const csv = `student,score
Alice,92
Bob,85
Charlie,88
Diana,95`;

  const result = parseCSV(csv);

  const avgScore = result.average("score");

  console.log(`Average score: ${avgScore.toFixed(2)}`);
}

// ============================================================================
// Example 10: Aggregation - Count
// ============================================================================

function example10Count() {
  console.log("\n=== Example 10: Count Aggregation ===\n");

  const csv = `name,department
John,Engineering
Jane,Sales
Bob,Engineering`;

  const result = parseCSV(csv);

  console.log(`Total employees: ${result.count()}`);
}

// ============================================================================
// Example 11: Aggregation - GroupBy
// ============================================================================

function example11GroupBy() {
  console.log("\n=== Example 11: GroupBy Aggregation ===\n");

  const csv = `name,department,salary
John,Engineering,80000
Jane,Sales,60000
Bob,Engineering,85000
Alice,Sales,62000
Charlie,HR,55000`;

  const result = parseCSV(csv);

  const groups = result.groupBy("department");

  for (const [dept, employees] of groups) {
    console.log(`\n${dept}: ${employees.length} employees`);
    for (const emp of employees) {
      console.log(`  ${emp.name}: $${emp.salary}`);
    }

    // Calculate average salary for this department
    const deptResult = result.filter((row) => row.department === dept);
    const avgSalary = deptResult.average("salary");
    console.log(`  Average salary: $${avgSalary.toFixed(2)}`);
  }
}

// ============================================================================
// Example 12: Complex Data Analysis
// ============================================================================

function example12ComplexAnalysis() {
  console.log("\n=== Example 12: Complex Data Analysis ===\n");

  const csv = `date,product,quantity,price,region
2024-01-01,Widget,100,10.50,North
2024-01-01,Gadget,50,25.00,South
2024-01-02,Widget,150,10.50,North
2024-01-02,Gadget,75,25.00,South
2024-01-03,Widget,120,10.50,East
2024-01-03,Doohickey,80,15.00,West`;

  const result = parseCSV(csv);

  // Total revenue
  const totalRevenue = result.rows.reduce(
    (sum, row) => sum + row.quantity * row.price,
    0
  );
  console.log(`Total Revenue: $${totalRevenue.toFixed(2)}`);

  // By product
  const products = result.groupBy("product");
  console.log("\nBy Product:");
  for (const [product, rows] of products) {
    const productRevenue = rows.reduce(
      (sum, row) => sum + row.quantity * row.price,
      0
    );
    console.log(`  ${product}: $${productRevenue.toFixed(2)}`);
  }

  // By region
  const regions = result.groupBy("region");
  console.log("\nBy Region:");
  for (const [region, rows] of regions) {
    const regionRevenue = rows.reduce(
      (sum, row) => sum + row.quantity * row.price,
      0
    );
    console.log(`  ${region}: $${regionRevenue.toFixed(2)}`);
  }
}

// ============================================================================
// Run all examples
// ============================================================================

function runAllExamples() {
  example1BasicParsing();
  example2QuotedFields();
  example3EscapedQuotes();
  example4TypeCoercion();
  example5CustomDelimiters();
  example6ErrorHandling();
  example7Filtering();
  example8Sum();
  example9Average();
  example10Count();
  example11GroupBy();
  example12ComplexAnalysis();

  console.log("\n=== All Examples Completed ===\n");
}

// Export for use in other modules
export {
  example1BasicParsing,
  example2QuotedFields,
  example3EscapedQuotes,
  example4TypeCoercion,
  example5CustomDelimiters,
  example6ErrorHandling,
  example7Filtering,
  example8Sum,
  example9Average,
  example10Count,
  example11GroupBy,
  example12ComplexAnalysis,
  runAllExamples,
};

// Run if this is the main module
if (require.main === module) {
  runAllExamples();
}

